(function() {
  var isLoaded = false;
  function asyncLoad() {
    if (isLoaded) return;
    isLoaded = true;
    var urls = ["https:\/\/s3.eu-west-1.amazonaws.com\/production-klarna-il-shopify-osm\/d3bc5d6366701989e2db5a93793900883f2d31a6\/terranova-og.myshopify.com-1769418965409.js?shop=terranova-og.myshopify.com"];
    for (var i = 0; i < urls.length; i++) {
      var s = document.createElement('script');
      s.type = 'text/javascript';
      s.async = true;
      s.src = urls[i];
      var x = document.getElementsByTagName('script')[0];
      x.parentNode.insertBefore(s, x);
    }
  };
  if(window.attachEvent) {
    window.attachEvent('onload', asyncLoad);
  } else {
    window.addEventListener('load', asyncLoad, false);
  }
})();

link.script:
      (function() {
        const ua = navigator.userAgent ? navigator.userAgent.toLowerCase() : '';
        const keys = ['mumble-app', 'shoppy'];
        const isWebview = keys.some((key) => ua.includes(key));

        if (isWebview) {
          document.documentElement.classList.add('webview');
        }

        window.__themeIsWebview = isWebview;
      })();

Sentry.onLoad(function () {
  Sentry.init({
    // Tracing
    tracesSampleRate: 1.0,
    // Session Replay
    replaysSessionSampleRate: 0.1,
    replaysOnErrorSampleRate: 1.0,
    // Filtro soft: solo errori dal nostro codice + api-interceptor + auth-debug
    beforeSend: function (event) {
      // Sempre: eventi dal nostro API interceptor
      if (event.tags && event.tags.source === 'api-interceptor') return event;
      // Sempre: diagnostica auth (TASK 6 — login bug investigation)
      if (event.tags && event.tags.source === 'auth-debug') return event;
      // Errori JS dal nostro codice (tema Shopify + pagine terranovastyle.com)
      if (event.exception && event.exception.values) {
        var allowedDomains = ['terranovastyle.com', 'cdn.shopify.com'];
        for (var i = 0; i < event.exception.values.length; i++) {
          var ex = event.exception.values[i];
          if (ex.stacktrace && ex.stacktrace.frames) {
            for (var j = 0; j < ex.stacktrace.frames.length; j++) {
              var filename = ex.stacktrace.frames[j].filename || '';
              if (allowedDomains.some(function (d) { return filename.indexOf(d) !== -1; })) {
                return event;
              }
            }
          }
        }
      }
      // Blocca errori da script terze parti (GTM, Klarna, Trustpilot, Selligent...)
      return null;
    }
  });
});

function feedback() {
  const p = window.Shopify.customerPrivacy;
  console.log(`Tracking ${p.userCanBeTracked() ? "en" : "dis"}abled`);
}
window.Shopify.loadFeatures(
  [
    {
      name: "consent-tracking-api",
      version: "0.1",
    },
  ],
  function (error) {
    if (error) throw error;
    if ("Cookiebot" in window)
      window.Shopify.customerPrivacy.setTrackingConsent({
        "analytics": false,
        "marketing": false,
        "preferences": false,
        "sale_of_data": false,
      }, () => console.log("Awaiting consent")
    );
  }
);

window.addEventListener("CookiebotOnConsentReady", function () {
  const C = Cookiebot.consent,
      existConsentShopify = setInterval(function () {
        if (window.Shopify.customerPrivacy) {
          clearInterval(existConsentShopify);
          window.Shopify.customerPrivacy.setTrackingConsent({
            "analytics": C["statistics"],
            "marketing": C["marketing"],
            "preferences": C["preferences"],
            "sale_of_data": C["marketing"],
          }, () => console.log("Consent captured"))
        }
      }, 100);
});

