    // qui controllo uno dei metafield perchè a volte manda il datalayer subito dopo il login, ma i meta non sono subito valorizzati
    
    /* END - Proprietà dell'utente */


    /* Custom function to get product data from product card */
    function getProductData(p, i) {
      const priceFinalDiv = p.querySelector(".prod-price > div");
      const priceFinal = priceFinalDiv 
        ? parseFloat(priceFinalDiv.textContent.replace('€','').replace(',','.')) 
        : 0;

      // prezzo listino se esiste
      const comparePriceDiv = p.querySelector(".prod-price-omnibus");
      const comparePrice = comparePriceDiv 
        ? parseFloat(comparePriceDiv.textContent.replace('€','').replace(',','.')) 
        : 0;

      // calcolo sconto solo se prezzo listino presente
      const data_discount = comparePrice ? (comparePrice - priceFinal) : 0;

      const variantButtons = p.querySelectorAll(".hover-variant-select .btn-variant");
      const allSizes = [];
      const availableSizes = [];
      const outOfStockSizes = [];

      variantButtons.forEach(btn => {
        const size = btn.textContent.trim();
        if (!size) return;
    
        allSizes.push(size);
        if (!btn.hasAttribute('disabled')) {
          availableSizes.push(size);
        } else {
          outOfStockSizes.push(size);
        }
      });

      return {
        item_id: p.dataset.id.slice(0, 13),
        item_name: p.querySelector(".prod-title a")?.textContent.trim() || '',
        discount: data_discount,
        ...(i !== undefined ? { index: i + 1 } : {}),
        item_brand: p.dataset.brand,
        item_category: data_page_firstLevelCategory,
        item_category2: data_page_secondLevelCategory,
        item_category3: data_page_thirdLevelCategory,
        item_category4: data_page_fourthLevelCategory,
        item_category5: data_page_fifthLevelCategory,
        item_variant: p.dataset.id.slice(0, 17),
        price: priceFinal,
        quantity: 1,
        item_availableSizes: allSizes.join(","),
        item_inStockSizes: availableSizes.join(","),
        item_outOfStockSizes: outOfStockSizes.join(","),
        item_commercialCategory: p.dataset.commCat,
        item_commercialType: p.dataset.commType,
        item_collection: data_page_siteWorld,
        item_idTagliaColore: p.dataset.id.slice(0, 17),
        item_coming_soon: p.dataset.cs
      };
    }
    /* END - Custom function to get product data */


    /* Custom function to get product data from cart item */
    function getCartProductData(p, i) {
      // prezzo listino se esiste
      const comparePriceDiv = p.querySelector(".compare-price");
      const comparePrice = comparePriceDiv 
        ? parseFloat(comparePriceDiv.textContent.replace('€','').replace(',','.')) 
        : 0;

      // calcolo sconto solo se prezzo listino presente
      const data_discount = comparePrice ? (comparePrice - parseFloat(p.dataset.price)) : 0;

      return {
        item_id: p.dataset.id.slice(0, 13),
        item_name: p.dataset.title,
        discount: data_discount,
        index: "undefined",
        item_brand: p.dataset.brand,
        item_category: data_page_firstLevelCategory,
        item_category2: data_page_secondLevelCategory,
        item_category3: data_page_thirdLevelCategory,
        item_category4: data_page_fourthLevelCategory,
        item_category5: data_page_fifthLevelCategory,
        item_variant: p.dataset.id.slice(0, 17),
        price: parseFloat(p.dataset.price),
        quantity: p.dataset.currentQuantity,
        item_availableSizes: "undefined",
        item_inStockSizes: "undefined",
        item_outOfStockSizes: "undefined",
        item_commercialCategory: p.dataset.commCat,
        item_commercialType: p.dataset.commType,
        item_collection: data_page_siteWorld,
        item_idTagliaColore: p.dataset.id.slice(0, 17) + p.dataset.variantTitle,
        item_coming_soon: p.dataset.cs
      };
    }
    /* END - Custom function to get product data */


    /* Helper per sincronizzare push degli eventi */
    var datalayerReady = {
      datalayer_loaded: false,
      user_info_loaded: false,
      callbacks: [],
      whenReady: function(callback) {
        if (this.datalayer_loaded && this.user_info_loaded) {
          callback();
        } else {
          this.callbacks.push(callback);
        }
      },
      markReady: function(event) {
        this[event] = true;
        if (this.datalayer_loaded && this.user_info_loaded) {
          this.callbacks.forEach(function(cb) { cb(); });
          this.callbacks = [];
        }
      }
    };
    /* END - Helper per sincronizzare push degli eventi */


    /* id_01 */
    window.dataLayer.push({
      'event': 'datalayer_loaded',
      'page_storeCountry': data_page_storeCountry,
      'page_type': data_page_type,
      'page_siteWorld': data_page_siteWorld,
      'page_levelCategory': data_page_levelCategory,        
      'page_firstLevelCategory': data_page_firstLevelCategory,
      'page_secondLevelCategory': data_page_secondLevelCategory,
      'page_thirdLevelCategory': data_page_thirdLevelCategory,
      'page_fourthLevelCategory': data_page_fourthLevelCategory,
      'page_fifthLevelCategory': data_page_fifthLevelCategory
    });
    datalayerReady.markReady('datalayer_loaded');
    /* END - id_01 */


    /* id_20 */
    window.dataLayer.push({
      'event': 'user_info_loaded',
      'user_status': data_user_status,
      
    });
    datalayerReady.markReady('user_info_loaded');
    /* END - id_20 */


    /* id_02 + id_04 + id_06 + id_07 */
    

    document.addEventListener("click", function(e) {
      const quantityBtn = e.target.closest("mc-cart-quantity button");
      const removeBtn = e.target.closest("mc-cart-remove");
      var eventName = "remove_from_cart";
      var cartItem = "";
      if (!quantityBtn && !removeBtn) return;

      if (quantityBtn) {
        cartItem = quantityBtn.closest(".p-cart-item");
      } else if (removeBtn) {
        cartItem = removeBtn.closest(".p-cart-item");
      }
      if (!cartItem) return;

      const productData = getCartProductData(cartItem);
      const oldQty = parseInt(productData.quantity, 10);
      let newQty = oldQty;

      if (quantityBtn) {
        if (quantityBtn.hasAttribute("data-minus")) {
          newQty = oldQty - 1;
        } else if (quantityBtn.hasAttribute("data-plus")) {
          newQty = oldQty + 1;
        }
      }

      eventName = newQty > oldQty ? "add_to_cart" : "remove_from_cart";
      console.log('riccardo', productData.price);

      window.dataLayer.push({
        event: eventName,
        ecommerce: {
          currency: data_currency,
          value: productData.price * newQty,
          items: [{
            ...productData,
            quantity: newQty
          }]
        }
      });
    });
    /* END - id_02 + id_04 + id_06 + id_07 */


