    document.addEventListener("click", function(e) {
      const btnSelectItem = e.target.closest("#next-select_item_to_return");
      const btnAddInfo = e.target.closest("#next-add_info_return");
      const btnConfirmInfo = e.target.closest("#next-confirm_info_return");

      if (btnSelectItem) {
        window.dataLayer.push({
          event: 'select_item_to_return'
        });
      } else if (btnAddInfo) {
        window.dataLayer.push({
          event: 'add_info_return'
        });
      } else if (btnConfirmInfo) {
        window.dataLayer.push({
          event: 'confirm_info_return'
        });
      } else {
        return;
      }
    });
    /* END - id_46 + id_47 + id_48 */


    /* id_45 */
    document.addEventListener("click", function(e) {
      const btnOnlineReturn = e.target.closest("#return-where-auth-online");
      const btnInStoreReturn = e.target.closest("#return-where-auth-store");

      if (btnOnlineReturn) {
        window.dataLayer.push({
          'event': 'select_method_return',
          'return_type': 'online'
        });
      } else if (btnInStoreReturn) {
        window.dataLayer.push({
          'event': 'select_method_return',
          'return_type': 'store'
        });
      } else {
        return;
      }
    });
    /* END - id_45 */


    /* id_65 */
