            .then((data) => {
              if (!data.variants || !data.variants.length) return;

              // Inject Bantoa button if enabled for this market
              if (showBantoa) {
                const firstAvailable = data.variants.find((v) => v.available) || data.variants[0];
                const sku = firstAvailable.sku || '';
                if (sku) {
                  const wrapper = slot.closest('.hover-img-wrapper');
                  if (wrapper && !wrapper.querySelector('.bantoa-btn')) {
                    const bantoaDiv = document.createElement('div');
                    bantoaDiv.className = 'vs-start-modal-visual vs-check-exists-product bantoa-btn position-absolute top-0 end-0 p-2 z-4 btn btn-sm btn-light align-items-center gap-1';
                    bantoaDiv.setAttribute('data-vs-item', sku);
                    bantoaDiv.setAttribute('data-vs-quality', '0.75');
                    bantoaDiv.setAttribute('data-vs-max-results', '100');
                    bantoaDiv.setAttribute('data-vs-min-results', '1');
                    bantoaDiv.setAttribute('data-vs-position', 'plp');
                    bantoaDiv.innerHTML = bantoaSvg;
                    wrapper.appendChild(bantoaDiv);
                  }
                }
              }

              // Skip variant injection if only default variant
              if (data.variants.length === 1 && data.variants[0].title === 'Default Title') return;

              let buttonsHtml = '';
              let hasAvailable = false;
              let hasUnavailable = false;
              for (let i = 0; i < data.variants.length; i++) {
                const v = data.variants[i];
                const vid = v.id;
                const name = v.title || '';
                if (v.available) {
                  hasAvailable = true;
                  buttonsHtml += `
${name}`;
                } else {
                  hasUnavailable = true;
                  buttonsHtml += `
${name}`;
                }
              }

              slot.innerHTML = `

${buttonsHtml}`;

              if (hasAvailable && !cartAddLoaded) {
                cartAddLoaded = true;
                themeComponent(theme.components['cart-add']);
              }
              if (hasUnavailable && !stoqLoaded) {
                stoqLoaded = true;
                loadComponent('./components/mc-stoq.js');
              }
            })
            .catch((e) => console.warn('[Clerk] variant fetch failed for', handle, e));
        });
      }

      // Inject Omnibus price into Clerk cards
      {
        const omnibusLabel = "Ultimo prezzo più basso";

        const injectOmnibus = function() {
          document.querySelectorAll('.clerk-omnibus-slot:not([data-omnibus-init])').forEach(function(slot) {
            slot.setAttribute('data-omnibus-init', '1');

            const variantId = slot.dataset.variantId;
            if (!variantId) return;

            var wrapper = document.createElement('div');
              wrapper.className = 'mt-2 d-flex align-items-center gap-1 xsmall d-none';
              wrapper.setAttribute('data-omnibus-block', '');
              wrapper.setAttribute('data-variant-id', variantId);
              wrapper.textContent = omnibusLabel + ': ';
              var boldEl = document.createElement('b');
              boldEl.setAttribute('data-omnibus-price', '');
              wrapper.appendChild(boldEl);
              slot.textContent = '';
              slot.appendChild(wrapper);

            if (window.updateOmnibusForVariant) window.updateOmnibusForVariant(variantId, slot);
          });
        };
        injectOmnibus();

        if (!window.updateOmnibusForVariant) {
          setTimeout(injectOmnibus, 500);
        }
      }
    });


    function checkWidgetsRendered() {
      setTimeout(function () {
        try {
          const clerkWidgets = document.querySelectorAll('.clerk');
          const productCount = document.querySelectorAll('.clerk .clerk-product').length;
          window.dispatchEvent(
            new CustomEvent('clerk:widgets:rendered', {
              detail: {
                count: clerkWidgets.length,
                productCount: productCount,
                hasProducts: productCount > 0
              }
            })
          );
        } catch (e) {
          // ignore
        }
      }, 2000);
    }

    document.addEventListener('DOMContentLoaded', function () {
      const storageKey = `clerk_visitor_id_${clerkPublicKey}`;
      (async function fetchVisitorId() {
        let storage = null;
        let visitorId = null;
        try {
          storage = window.sessionStorage;
          if (storage) visitorId = storage.getItem(storageKey);

          if (!visitorId) {
            const response = await fetch(
              `https://api.clerk.io/v2/misc/visitor_id?key=${encodeURIComponent(clerkPublicKey)}&visitor=auto`
            );
            if (response.ok) {
              const data = await response.json();
              visitorId = data && data.visitor;
              if (visitorId && storage) storage.setItem(storageKey, visitorId);
            }
          }

          if (visitorId) {
            window.Clerk('config', { visitor: visitorId });
            window.__clerk_visitor_id = visitorId;
          }
        } catch (e) {
          // ignore (do not hard-fail on visitor id)
        } finally {
          const analytics = window.Shopify && window.Shopify.analytics;
          if (analytics && typeof analytics.publish === 'function') {
            analytics.publish('clerk_pixel_context', {
              localeApiKey: clerkPublicKey,
              visitor: visitorId || null
            });
          }
          notifyClerkReady();
          checkWidgetsRendered();
        }
      })();
    });
  })();

(() => {
  if (window.__omnibusPriceUpdater) return;
  window.__omnibusPriceUpdater = true;

  const countryCode = "SM";
  const languageCode = "it";
  const featureNode = document.getElementById('shopify-features');
  let storefrontToken = null;

  if (featureNode) {
    try {
      storefrontToken = JSON.parse(featureNode.textContent).accessToken;
    } catch (error) {
      console.warn('[Omnibus] Cannot read Storefront token', error);
    }
  }

  if (!storefrontToken || !countryCode) return;

  const omnibusCountriesStrict = ['PL', 'CZ', 'SK'];

  const query = `
    query OmnibusPrice($id: ID!, $country: CountryCode, $countryKey: String!) @inContext(country: $country) {
      node(id: $id) {
        ... on ProductVariant {
          id
          price { amount currencyCode }
          compareAtPrice { amount currencyCode }
          requiresShipping
          omnibusDefault: metafield(namespace: "app--320503809--omnibus", key: "price") { value type key }
          omnibusCountry: metafield(namespace: "app--320503809--omnibus", key: $countryKey) { value type key }
        }
      }
    }
  `;

  const endpoint = '/api/2024-07/graphql.json';
  const cache = {};

  const formatMoney = (amount, currency) => {
    try {
      return new Intl.NumberFormat((languageCode || 'en').replace('_', '-'), {
        style: 'currency',
        currency
      }).format(amount);
    } catch (error) {
      return `${amount.toFixed(2)} ${currency || ''}`.trim();
    }
  };

  const parseVariantId = (id) => id?.replace('gid://shopify/ProductVariant/', '');

  const updateDom = (variantId, data, scope) => {
    const container = scope || document;
    const blocks = container.querySelectorAll('[data-omnibus-block]');
    if (!blocks.length) return;

    const hasOmnibus = typeof data?.omnibusAmount === 'number' && !Number.isNaN(data.omnibusAmount) && data.omnibusAmount > 0;
    const isDigital = data?.requiresShipping === false;
    const isStrictCountry = omnibusCountriesStrict.indexOf(countryCode) > -1;
    const omnibusEqualsPrice = hasOmnibus && data.omnibusAmount === data.priceAmount;
    const omnibusEqualsCompare = hasOmnibus && data.compareAtPriceAmount != null && data.omnibusAmount === data.compareAtPriceAmount;
    const hideForNonStrict = !isStrictCountry && (omnibusEqualsPrice || omnibusEqualsCompare);

    blocks.forEach((block) => {
      block.dataset.variantId = String(variantId || block.dataset.variantId || '');
      const priceEl = block.querySelector('[data-omnibus-price]');
      const discountEl = block.querySelector('[data-omnibus-discount]');
      const discountWrapper = block.querySelector('[data-omnibus-discount-wrapper]');

      if (!hasOmnibus || isDigital || hideForNonStrict) {
        block.classList.add('d-none');
        return;
      }

      block.classList.remove('d-none');

      if (priceEl) {
        priceEl.textContent = formatMoney(data.omnibusAmount, data.currency);
      }

      // Discount: (omnibus - currentPrice) / omnibus * 100, shown as -XX%
      // Only when currentPrice < omnibus
      if (discountEl) {
        const pct = data.omnibusAmount > 0 && data.priceAmount < data.omnibusAmount
          ? Math.floor((data.omnibusAmount - data.priceAmount) * 100 / data.omnibusAmount)
          : 0;

        discountEl.textContent = pct > 0 ? `-${pct}%` : '';
        discountWrapper?.classList?.toggle('d-none', pct <= 0);
      }
    });
  };

  const parseMoney = (meta, fallbackCurrency) => {
    if (!meta?.value) return null;
    try {
      const parsed = JSON.parse(meta.value);
      const amount = typeof parsed === 'number' ? parsed : parsed.amount;
      const currency = parsed.currency_code || parsed.currencyCode || fallbackCurrency;
      const num = parseFloat(amount);
      if (!Number.isNaN(num)) return { amount: num, currency };
    } catch (e) {
      const num = parseFloat(meta.value);
      if (!Number.isNaN(num)) return { amount: num, currency: fallbackCurrency };
    }
    return null;
  };

  const fetchVariantData = async (variantId) => {
    const gid = `gid://shopify/ProductVariant/${variantId}`;
    const cacheKey = `${gid}-${countryCode}`;
    if (cache[cacheKey]) return cache[cacheKey];

    const response = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Shopify-Storefront-Access-Token': storefrontToken
      },
      body: JSON.stringify({
        query,
        variables: { id: gid, country: countryCode, countryKey: `price-${countryCode}` }
      })
    });

    if (!response.ok) throw new Error(`Storefront API error: ${response.status}`);

    const payload = await response.json();
    const variant = payload?.data?.node;
    if (!variant) return null;

    // Priority: country-specific (price-PL) → default (price)
    // These metafields already store the amount in local currency (e.g. PLN)
    const meta = variant.omnibusCountry || variant.omnibusDefault;
    const moneyData = parseMoney(meta, variant.price?.currencyCode);
    const omnibusAmount = moneyData?.amount ?? null;
    const currency = moneyData?.currency || variant.price?.currencyCode;
    const priceAmount = variant.price ? parseFloat(variant.price.amount) : null;
    const compareAtPriceAmount = variant.compareAtPrice ? parseFloat(variant.compareAtPrice.amount) : null;

    const cleaned = { omnibusAmount, currency, priceAmount, compareAtPriceAmount, requiresShipping: variant.requiresShipping };
    cache[cacheKey] = cleaned;
    return cleaned;
  };

  const updateForVariant = async (variantId, scope) => {
    if (!variantId) return;
    try {
      const data = await fetchVariantData(variantId);
      updateDom(variantId, data, scope);
    } catch (error) {
      console.warn('[Omnibus] Failed to update variant', variantId, error);
    }
  };

  const init = () => {
    const blocks = document.querySelectorAll('[data-omnibus-block]');
    if (!blocks.length) return;

    const initialId = blocks[0].dataset.variantId;
    updateForVariant(initialId);
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  // Expose for external callers (e.g. Clerk product injection)
  window.updateOmnibusForVariant = updateForVariant;

  window.addEventListener('variant:select', (event) => {
    const url = event?.detail?.url;
    if (!url) return;
    const variantId = new URL(url, window.location.origin).searchParams.get('variant');
    updateForVariant(parseVariantId(variantId || ''));
  });
})();

