// Helper to parse JSON strings (for arrays stored in DynamoDB)
// Also normalizes all values to strings for consistent ID comparison
function parseJsonSafe(val, fallback) {
  if (!val) return fallback;

  let result = val;

  // If it's a string, try to parse it as JSON
  if (typeof val === 'string') {
    // Check if it looks like a JSON array
    const trimmed = val.trim();
    if (trimmed.startsWith('[')) {
      try {
        result = JSON.parse(trimmed);
      } catch(e) {
        return fallback;
      }
    } else {
      // Not JSON, return fallback
      return fallback;
    }
  }

  // Ensure result is an array
  if (!Array.isArray(result)) return fallback;

  // Normalize all values to strings (handles number IDs)
  return result.map(function(item) {
    if (item === null || item === undefined) return '';
    // Extract numeric ID if it's a Shopify GID
    const str = String(item);
    if (str.includes('gid://shopify/')) {
      return str.split('/').pop() || str;
    }
    return str;
  }).filter(function(item) {
    return item !== '';
  });
}

