const header = document.querySelector('nav.navbar');
const searchPanel = header?.querySelector('[data-header-search-panel]');
const openBtn = header?.querySelector('[data-search-toggle="open"]');

const openSearch = () => {
  if (!searchPanel) return;
  searchPanel.classList.remove('d-none');
  searchPanel.classList.add('d-flex');
  const input = searchPanel.querySelector('input[type="search"]');
  if (input) {
    requestAnimationFrame(() => input.focus());
  }
};

const closeSearch = () => {
  if (!searchPanel) return;
  searchPanel.classList.add('d-none');
  searchPanel.classList.remove('d-flex');
};

openBtn?.addEventListener('click', (event) => {
  event.preventDefault();
  openSearch();
});

header?.addEventListener('click', (event) => {
  const closeTarget = event.target.closest('[data-search-toggle="close"]');
  if (!closeTarget) return;
  event.preventDefault();
  closeSearch();
});

document.addEventListener('keydown', (event) => {
  if (event.key === 'Escape' && searchPanel && !searchPanel.classList.contains('d-none')) {
    closeSearch();
  }
});

section.script:
(function initClerkFallbackHandler() {
  'use strict';

  const CONFIG = {
    clerkSelector: "#clerk-widget-section-template--24917283373434__clerk_or_recommendations_W4J7w7.clerk",
    recWrapperSelector: "[data-fallback-wrapper=\"template--24917283373434__clerk_or_recommendations_W4J7w7\"]",
    recRootSelector: ".product-recommendations[data-product-recommendations-root=\"1\"]",
    timeoutMs: 3000,
    fallbackType: "carousel",
    productSelectors: '.clerk-product, [data-clerk-product-id], .clerk-product-card, .clerk-slider-item',
    sliderSelector: '.clerk-slider, .clerk-carousel',
    debugMode: true
  };

  const state = {
    fallbackTriggered: false,
    observer: null,
    timeoutId: null,
    listeners: []
  };

  function log(message, data) {
    if (!CONFIG.debugMode) return;
    if (data !== undefined) {
      console.log('[ClerkFallback] ' + message, data);
    } else {
      console.log('[ClerkFallback] ' + message);
    }
  }

  function cleanup() {
    if (state.observer) {
      state.observer.disconnect();
      state.observer = null;
    }
    if (state.timeoutId) {
      clearTimeout(state.timeoutId);
      state.timeoutId = null;
    }
    state.listeners.forEach(function(item) {
      window.removeEventListener(item.event, item.handler);
    });
    state.listeners = [];
    log('Cleanup completato');
  }

  function addTrackedListener(eventName, handler, options) {
    window.addEventListener(eventName, handler, options);
    state.listeners.push({ event: eventName, handler: handler });
  }

  function clerkHasValidContent(clerkRoot) {
    if (!clerkRoot) {
      log('clerkRoot è null');
      return false;
    }

    const products = clerkRoot.querySelectorAll(CONFIG.productSelectors);
    if (products.length > 0) {
      log('Trovati ' + products.length + ' prodotti Clerk');
      return true;
    }

    const slider = clerkRoot.querySelector(CONFIG.sliderSelector);
    if (slider) {
      const sliderItems = slider.querySelectorAll('li, .clerk-slider-item');
      if (sliderItems.length > 0) {
        log('Slider ha ' + sliderItems.length + ' prodotti');
        return true;
      }
    }

    log('Nessun contenuto Clerk valido trovato');
    return false;
  }

  function loadRecommendations(recRoot) {
    // Pattern fetch diretto di terranova (da sections/product-recommendations.liquid)
    var dataUrl = recRoot.dataset.url;
    if (!dataUrl) {
      log('Nessun data-url trovato su recRoot');
      return;
    }

    fetch(dataUrl)
      .then(function(response) { return response.text(); })
      .then(function(text) {
        var html = document.createElement('div');
        html.innerHTML = text;
        var recommendations = html.querySelector('.product-recommendations');

        if (recommendations && recommendations.innerHTML.trim().length) {
          // Inject styles into head FIRST
          var styles = recommendations.querySelectorAll('style');
          styles.forEach(function(style) {
            document.head.appendChild(style.cloneNode(true));
          });

          // Then update the content
          recRoot.innerHTML = recommendations.innerHTML;

          // Force lazy images to load
          recRoot.querySelectorAll('img[loading="lazy"]').forEach(function(img) {
            img.loading = 'eager';
          });

          // Load swiper component
          if (recRoot.querySelectorAll('mc-swiper').length > 0 && window.loadComponent) {
            window.loadComponent('./components/mc-swiper.js');
          }
        }
      })
      .catch(function(e) {
        console.error('[ClerkFallback] Errore nel caricamento delle raccomandazioni:', e);
      });
  }

  function showRecommendations(reason) {
    if (state.fallbackTriggered) {
      log('Fallback già attivato, ignoro');
      return;
    }

    state.fallbackTriggered = true;
    cleanup();

    log('Attivazione fallback (' + CONFIG.fallbackType + '): ' + reason);

    const recWrapper = document.querySelector(CONFIG.recWrapperSelector);
    if (!recWrapper) {
      log('Wrapper fallback non trovato');
      return;
    }

    const clerkRoot = document.querySelector(CONFIG.clerkSelector);
    const clerkContainer = clerkRoot ? clerkRoot.closest('[data-clerk-widget-root]') : document.querySelector('#clerk-widget');
    if (clerkContainer) {
      clerkContainer.style.display = 'none';
    }

    recWrapper.style.display = '';

    if (CONFIG.fallbackType === 'carousel') {
      // Carousel is already server-rendered, re-init swipers after becoming visible
      setTimeout(function() {
        var swipers = recWrapper.querySelectorAll('mc-swiper');
        swipers.forEach(function(el) {
          if (el.swiper) el.swiper.update();
        });
        window.dispatchEvent(new Event('resize'));
      }, 200);
      log('Carousel fallback mostrato');
    } else {
      var recRoot = recWrapper.querySelector(CONFIG.recRootSelector);
      if (recRoot) {
        loadRecommendations(recRoot);
        log('Recommendations caricate via fetch');
      } else {
        log('Elemento recommendations root non trovato');
      }
    }

    try {
      window.dispatchEvent(new CustomEvent('clerk:fallback:activated', {
        detail: { reason: reason, type: CONFIG.fallbackType, timestamp: Date.now() }
      }));
    } catch (e) {
    }
  }

  function clerkLoadedSuccessfully() {
    if (state.fallbackTriggered) return;

    cleanup();
    log('Clerk caricato con successo, nessun fallback necessario');

    try {
      window.dispatchEvent(new CustomEvent('clerk:fallback:not-needed', {
        detail: { timestamp: Date.now() }
      }));
    } catch (e) {
    }
  }

  function initMutationObserver(clerkRoot) {
    if (!clerkRoot || !window.MutationObserver) {
      log('MutationObserver non disponibile o clerkRoot mancante');
      return;
    }

    state.observer = new MutationObserver(function(mutations) {
      for (let i = 0; i < mutations.length; i++) {
        const mutation = mutations[i];
        if (mutation.type === 'childList' && mutation.addedNodes.length > 0) {
          if (clerkHasValidContent(clerkRoot)) {
            clerkLoadedSuccessfully();
            return;
          }
        }
      }
    });

    state.observer.observe(clerkRoot, {
      childList: true,
      subtree: true
    });

    log('MutationObserver inizializzato');
  }

  function handleHardFail(event) {
    const reason = event && event.detail && event.detail.reason ? event.detail.reason : 'unknown';
    showRecommendations('hard_fail: ' + reason);
  }

  function handleWidgetsRendered(event) {
    log('clerk:widgets:rendered ricevuto', event && event.detail);

    setTimeout(function() {
      const clerkRoot = document.querySelector(CONFIG.clerkSelector);

      if (!clerkHasValidContent(clerkRoot)) {
        log('clerk:widgets:rendered ma nessun prodotto trovato');
        showRecommendations('no_products_after_render');
      } else {
        clerkLoadedSuccessfully();
      }
    }, 500);
  }

  function init() {
    log('Inizializzazione handler');

    if (window.__clerkHardFail) {
      showRecommendations('pre_init_hard_fail: ' + (window.__clerkHardFail.reason || 'unknown'));
      return;
    }

    var clerkRoot = document.querySelector(CONFIG.clerkSelector);

    if (!clerkRoot) {
      log('Container Clerk non trovato');
      showRecommendations('no_clerk_container');
      return;
    }

    if (clerkHasValidContent(clerkRoot)) {
      clerkLoadedSuccessfully();
      return;
    }

    initMutationObserver(clerkRoot);

    addTrackedListener('clerk:hard-fail', handleHardFail, { once: true });
    addTrackedListener('clerk:widgets:rendered', handleWidgetsRendered, { once: true });

    state.timeoutId = setTimeout(function() {
      log('Timeout scaduto (' + CONFIG.timeoutMs + 'ms)');

      if (state.fallbackTriggered) {
        log('Fallback già attivato, ignoro timeout');
        return;
      }

      const clerkRoot = document.querySelector(CONFIG.clerkSelector);

      if (!clerkHasValidContent(clerkRoot)) {
        showRecommendations('timeout_' + CONFIG.timeoutMs + 'ms');
      } else {
        clerkLoadedSuccessfully();
      }
    }, CONFIG.timeoutMs);

    log('Timeout impostato: ' + CONFIG.timeoutMs + 'ms');
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    setTimeout(init, 50);
  }
})();

footer.script:
window.addEventListener('DOMContentLoaded', function() {
  try {
    const pathname = window.location.pathname;
    let redirectUrl = '';
    
    if ('SM' === 'SM' && !pathname.startsWith('/it-it')) {
      redirectUrl = `/it-it${pathname}`;
    } else if (pathname.endsWith('/') && pathname !== '/') {
      redirectUrl = window.location.href.replace(pathname, pathname.slice(0, -1));
    }
    
    if (redirectUrl) {
      window.location.href = redirectUrl;
    }
  } catch(error) {
    console.log(error);
  }
});

